interface Chunk { text: string; start: number; end: number; }

function chunkDocument(document: string, chunkTokens: number, overlapTokens: number): Chunk[] {
  const chunkChars = chunkTokens * 4;
  const overlapChars = overlapTokens * 4;
  const stepChars = chunkChars - overlapChars;

  if (stepChars <= 0) throw new Error('overlapTokens must be less than chunkTokens');

  const chunks: Chunk[] = [];
  let start = 0;

  while (start < document.length) {
    let end = start + chunkChars;

    if (end >= document.length) {
      // Last chunk
      chunks.push({ text: document.slice(start), start, end: document.length });
      break;
    }

    // Try to break at a word boundary
    let breakAt = end;
    const spaceIdx = document.lastIndexOf(' ', end);
    if (spaceIdx > start) {
      breakAt = spaceIdx;
    }

    chunks.push({ text: document.slice(start, breakAt).trimEnd(), start, end: breakAt });

    // Advance by step, but start overlap chars back
    start = breakAt - overlapChars;
    // Skip whitespace at new start
    while (start < document.length && document[start] === ' ') start++;
  }

  return chunks;
}
